def hashcode(n: int) -> str:
    return hashlib.sha256(str(n).encode('utf-8')).hexdigest()

@pytest.mark.parametrize("board, diceRolls, result, testcase", q7_testcases)
def test_q7(board, diceRolls, result, testcase):
    if testcase == True:
        assert playSandL(board, diceRolls) == result
    else:
        assert hashcode(playSandL(board, diceRolls)) == result